import type {
  SplitterGroupEmits as HeadlessSplitterGroupEmits,
  SplitterGroupProps as HeadlessSplitterGroupProps,
  SplitterPanelEmits as HeadlessSplitterPanelEmits,
  SplitterPanelProps as HeadlessSplitterPanelProps,
  SplitterResizeHandleEmits as HeadlessSplitterResizeHandleEmits,
  SplitterResizeHandleProps as HeadlessSplitterResizeHandleProps,
  SplitterUi
} from '@soybeanjs/headless/splitter';
import type { ClassValue } from '@soybeanjs/headless/types';
import type { ThemeSize } from '@/theme';

/**
 * Properties for the SplitterGroup component.
 */
export interface SplitterGroupProps extends HeadlessSplitterGroupProps {
  /**
   * Additional class names applied to the root element.
   */
  class?: ClassValue;
  /**
   * Per-slot class overrides for the component.
   */
  ui?: Partial<SplitterUi>;
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
}

/**
 * Events for the SplitterGroup component.
 */
export type SplitterGroupEmits = HeadlessSplitterGroupEmits;

/**
 * Properties for the SplitterPanel component.
 */
export interface SplitterPanelProps extends HeadlessSplitterPanelProps {
  /**
   * Additional class names applied to the root element.
   */
  class?: ClassValue;
}

/**
 * Events for the SplitterPanel component.
 */
export type SplitterPanelEmits = HeadlessSplitterPanelEmits;

/**
 * Properties for the SplitterResizeHandle component.
 */
export interface SplitterResizeHandleProps extends HeadlessSplitterResizeHandleProps {
  /**
   * Additional class names applied to the root element.
   */
  class?: ClassValue;
  /**
   * Whether with handle.
   */
  withHandle?: boolean;
}

/**
 * Events for the SplitterResizeHandle component.
 */
export type SplitterResizeHandleEmits = HeadlessSplitterResizeHandleEmits;

export { default as SSplitterGroup } from './splitter-group.vue';
export { default as SSplitterPanel } from './splitter-panel.vue';
export { default as SSplitterResizeHandle } from './splitter-resize-handle.vue';

export type * from './types';

// @unocss-include
import { scv } from '@soybeanjs/cva';

export const splitterVariants = scv({
  slots: {
    root: 'flex h-full w-full data-[orientation=vertical]:flex-col',
    panel: 'min-h-0 min-w-0',
    resizeHandle: [
      'bg-border focus-visible:ring-ring relative flex w-px cursor-col-resize items-center justify-center transition-colors duration-200 after:absolute after:inset-y-0',
      'after:start-1/2 after:-translate-x-1/2 outline-none focus-visible:ring-1 focus-visible:ring-offset-1',
      'data-[state=hover]:bg-accent data-[state=drag]:bg-accent',
      'data-[disabled]:cursor-not-allowed data-[disabled]:opacity-60',
      'data-[orientation=vertical]:h-px data-[orientation=vertical]:w-full',
      'data-[orientation=vertical]:cursor-row-resize',
      'data-[orientation=vertical]:after:start-0 data-[orientation=vertical]:after:w-full',
      'data-[orientation=vertical]:after:-translate-y-1/2 data-[orientation=vertical]:after:translate-x-0'
    ]
  },
  variants: {
    size: {
      xs: {
        resizeHandle: 'after:w-0.5 data-[orientation=vertical]:after:h-0.5'
      },
      sm: {
        resizeHandle: 'after:w-0.75 data-[orientation=vertical]:after:h-0.75'
      },
      md: {
        resizeHandle: 'after:w-1 data-[orientation=vertical]:after:h-1'
      },
      lg: {
        resizeHandle: 'after:w-1.25 data-[orientation=vertical]:after:h-1.25'
      },
      xl: {
        resizeHandle: 'after:w-1.5 data-[orientation=vertical]:after:h-1.5'
      },
      '2xl': {
        resizeHandle: 'after:w-2 data-[orientation=vertical]:after:h-2'
      }
    }
  },
  defaultVariants: {
    size: 'md'
  }
});

import type { ThemeSize } from './types';

export const themeSizeMap: Record<ThemeSize, number> = {
  xs: 12,
  sm: 14,
  md: 16,
  lg: 18,
  xl: 20,
  '2xl': 24
};
export const miniSizeMap: Record<ThemeSize, ThemeSize> = {
  xs: 'xs',
  sm: 'xs',
  md: 'sm',
  lg: 'md',
  xl: 'lg',
  '2xl': 'xl'
};

export const themeSizeRatio = Object.fromEntries(
  Object.entries(themeSizeMap).map(([key, value]) => [key, value / themeSizeMap.md])
) as Record<ThemeSize, number>;
